-- Legacy Nexus seed data
-- Aplicado por db.py al primer arranque si no existe data/legacy.db

PRAGMA foreign_keys = OFF;

-- Schema -----------------------------------------------------------

CREATE TABLE users (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    username TEXT NOT NULL UNIQUE,
    password TEXT NOT NULL,
    is_admin INTEGER NOT NULL DEFAULT 0
);

CREATE TABLE suppliers (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    contact TEXT,
    country TEXT
);

CREATE TABLE warehouses (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    region TEXT
);

CREATE TABLE products (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    sku TEXT,
    name TEXT,
    description TEXT,
    price REAL,
    category TEXT,
    supplier_id INTEGER,
    created_at TEXT,
    updated_at TEXT,
    deleted_at TEXT
);

CREATE TABLE inventory_stock (
    product_id INTEGER,
    warehouse_id INTEGER,
    quantity INTEGER
);

CREATE TABLE inventory_movements (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    product_id INTEGER,
    warehouse_id INTEGER,
    qty INTEGER,
    type TEXT,
    ref_id INTEGER,
    ts TEXT
);

CREATE TABLE sales (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER,
    product_id INTEGER,
    customer_type TEXT,
    subtotal REAL,
    total TEXT,
    status TEXT,
    last_touch_at TEXT,
    created_at TEXT
);

CREATE TABLE sale_items (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    sale_id INTEGER,
    product_id INTEGER,
    qty INTEGER,
    unit_price REAL
);

CREATE TABLE purchases (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    supplier_id INTEGER,
    total NUMERIC,
    received_date TEXT,
    bank_ref TEXT,
    status TEXT
);

CREATE TABLE purchase_items (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    purchase_id INTEGER,
    product_id INTEGER,
    qty INTEGER,
    unit_cost REAL
);

CREATE TABLE audit_log (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    entity TEXT,
    entity_id INTEGER,
    old_value TEXT,
    new_value TEXT,
    ts TEXT
);

CREATE TABLE notifications (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER,
    message TEXT,
    kind TEXT,
    status TEXT,
    created_at TEXT
);

CREATE TABLE refunds (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    sale_id INTEGER,
    user_id INTEGER,
    reason TEXT,
    amount TEXT,
    status TEXT,
    approved_by INTEGER,
    created_at TEXT
);

-- Triggers ---------------------------------------------------------

CREATE TRIGGER trg_apply_legacy_discount
AFTER INSERT ON sales
FOR EACH ROW
WHEN NEW.customer_type = 'LEGACY_A'
BEGIN
    UPDATE sales SET subtotal = NEW.subtotal * 0.85,
                     total = CAST(CAST(NEW.subtotal * 0.85 * 1.16 AS REAL) AS TEXT)
    WHERE id = NEW.id;
END;

CREATE TRIGGER trg_update_last_touch
AFTER UPDATE OF status ON sales
FOR EACH ROW
BEGIN
    UPDATE sales SET last_touch_at = datetime('now') WHERE id = NEW.id;
END;

CREATE TRIGGER trg_audit_price_change
AFTER UPDATE OF price ON products
FOR EACH ROW
WHEN OLD.price IS NOT NULL AND NEW.price IS NOT NULL AND OLD.price != NEW.price
BEGIN
    VALUES ('products.price', NEW.id, CAST(OLD.price AS TEXT), CAST(NEW.price AS TEXT), datetime('now'));
END;

